import './TreeNode.scss';

import { Avatar } from ':components/Avatar';
import { Checkbox } from ':components/Checkbox';
import { Icon } from ':components/Icon';
import { IconButton } from ':components/IconButton';
import { Tooltip } from ':components/Tooltip';
import { Typography } from ':components/Typography';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useEffect, useRef, useState } from 'react';

import { classNames } from '../../../helpers/classnames';
import type { Node } from '../Tree.types';
import { CheckboxStatus } from '../Tree.types';
import { useTreeContext } from '../TreeContext';
import type { TreeNodeProps } from './TreeNode.types';

export const TreeNode: React.FC<TreeNodeProps> = ({
	title,
	children,
	avatar,
	icon,
	style,
	className = '',
	id,
	disabled = false,
	checked = false,
	expanded = false,
	custom,
}): React.JSX.Element => {
	const {
		selectedId,
		toggleSingleSelect,
		nodes,
		registerNode,
		toggleExpansion,
		toggleCheckbox,
		treeParams,
		recursiveExpansion,
		deleteNode,
	} = useTreeContext();

	const multiselect = treeParams.multiselect;
	const isSelected = id === selectedId && !multiselect;
	const amount = treeParams.amount;
	const size = treeParams.size;
	const expandOnArrow = treeParams.expandOnArrow; // общие параметры дерева из контекста

	const titleRef = useRef<HTMLElement | null>(null); // реф для отслеживания обрезан текст или нет
	const [isWrapped, setIsWrapped] = useState(false); // стейт для вывода тултипа

	const [firstRender, setFirstRender] = useState(true);
	const childrenWithProps = React.Children.map(children, child => {
		// для дочерних элементов прокидываем disabled
		if (React.isValidElement<TreeNodeProps>(child) && child.type === TreeNode) {
			return React.cloneElement(child, {
				disabled: disabled,
				...child.props,
			});
		}
		return child;
	});

	useEffect(() => {
		if (!nodes[id]) {
			setFirstRender(true); // если нода до этого не была в контексте, т. е. отрендерилась в первый раз, меняем этот пропс
		}

		const node: Node = {
			id: id,
			checked: checked ? CheckboxStatus.CHECKED : CheckboxStatus.UNCHECKED,
			disabled: disabled,
			expanded: firstRender ? expanded : nodes[id]?.expanded, // поменять тут если не нужно хранить состояние свернутости\развернутости вложенных элементов после закрытия родительского

			children: children
				? React.Children.map(children, child => {
						// собираем в массив все идшники дочерних компонентов
						if (React.isValidElement<TreeNodeProps>(child) && child.type === TreeNode && child.props.id) {
							return child.props.id;
						}
					}).filter(Boolean)
				: [],
		};

		new Promise<void>((resolve, reject) => {
			registerNode(node);
			resolve();
		})
			.then(() => {
				if (!firstRender) {
					return;
				}
				if (checked) {
					// если компонент рендерится в первый раз, то применяем параметры с пропсов
					recursiveExpansion(id); // тут мы считаем, что если элемент выбран то это значит что надо так же развернуть все элементы до него
				} else if (expanded) {
					recursiveExpansion(id); // поменять тут на toggleExpansion если рекурсивное раскрытие не требуется
				}
			})
			.finally(() => {
				setFirstRender(false);
			});

		return () => {
			deleteNode(id);
		};
	}, [children, checked]);

	// useEffect(() => {
	// if (!firstRender) {
	// 	return;
	// }
	// if (checked) {
	// 	// если компонент рендерится в первый раз, то применяем параметры с пропсов
	// 	recursiveExpansion(id); // тут мы считаем, что если элемент выбран то это значит что надо так же развернуть все элементы до него
	// } else if (expanded) {
	// 	recursiveExpansion(id); // поменять тут на toggleExpansion если рекурсивное раскрытие не требуется
	// }
	// }, [firstRender]);

	useEffect(() => {
		const checkWrap = (): void => {
			// проверяем обрезан ли текст
			setIsWrapped(titleRef.current.scrollWidth > titleRef.current.clientWidth);
		};

		checkWrap();

		window.addEventListener('resize', checkWrap); // на каждый ресайз будем проверять обрезан он или нет

		return () => {
			window.removeEventListener('resize', checkWrap);
		};
	}, [title]);

	const isFinalSingleselect =
		!multiselect && !React.Children.count(children) && !disabled && !className.includes('tree_title');

	const handleNodeClick = (event?: React.MouseEvent<HTMLElement>): void => {
		if (
			// обрабатываем клик на ноду, в зависимости от режима мультиселетк или синглселетк
			isFinalSingleselect
		) {
			toggleSingleSelect(id);
		}
		if (!expandOnArrow && React.Children.count(children)) {
			// если нужно разворачивать ноду по клику не только на стрелку
			toggleExpansion(id, event);
		}
	};

	return (
		<>
			<li
				role="treeitem"
				data-testid="TreeNode"
				className={classNames(
					`treenode-${size}`,
					Object.keys(children || {}).length === 0 && 'treenode-last',
					className,
					disabled && 'treenode-disable',
					isSelected && 'treenode-selected',
				)}
				aria-expanded={expanded}
				aria-selected={isSelected}
				tabIndex={0}
				onClick={disabled ? undefined : event => handleNodeClick(event)}
				onKeyDown={
					disabled
						? undefined
						: (event): void => {
								if (event.key === 'Enter' || event.key === ' ') {
									event.preventDefault();
									handleNodeClick();
								}
							}
				}
				style={style}
			>
				{Object.keys(children || {}).length > 0 && (
					<IconButton
						size="large"
						onClick={(event): void => {
							event.stopPropagation();
							toggleExpansion(id, event);
						}}
						iconName={nodes[id]?.expanded ? Icons.NavArrowDown : Icons.NavArrowRight}
					/>
				)}

				{multiselect && !className.includes('tree_title') && (
					<div
						role="button"
						tabIndex={0}
						onClick={(event): void => event.stopPropagation()}
						onKeyDown={(event): void => {
							if (event.key === 'Enter' || event.key === ' ') {
								event.preventDefault();
								event.stopPropagation();
							}
						}}
					>
						<Checkbox
							onClick={(): void => {
								toggleCheckbox(id);
							}}
							onChange={(): void => {}}
							checked={!!(nodes[id]?.checked !== CheckboxStatus.UNCHECKED)}
							disabled={disabled}
							type={nodes[id]?.checked === CheckboxStatus.PARTIALLY ? 'indeterminate' : 'checkbox'}
						></Checkbox>
					</div>
				)}

				{avatar && (
					<div className="treenode_aiwrapper">
						<Avatar
							{...avatar}
							size={size === 'large' ? 'medium' : 'small'}
							variant={'circle'}
							type={'default'}
						></Avatar>
					</div>
				)}
				{icon && (
					<div className="treenode_aiwrapper">
						<Icon {...icon} size={size} />
					</div>
				)}

				<Tooltip title={title} disableHover={!isWrapped}>
					<Typography ref={titleRef} className={'treenode_title'} variant={'body3'}>
						{title}
					</Typography>
				</Tooltip>
				<div
					className="treenode_custom"
					role="button"
					tabIndex={0}
					onClick={(event): void => event.stopPropagation()}
					onKeyDown={(event): void => {
						if (event.key === 'Enter' || event.key === ' ') {
							event.preventDefault();
							event.stopPropagation();
						}
					}}
				>
					{custom}
					{amount && Boolean(React.Children.count(children)) && (
						<span className="treenode_amount">{React.Children.count(children)}</span>
					)}
				</div>
			</li>
			<div
				role="group"
				className={classNames(`treenode_subnodes-${size}`, nodes[id]?.expanded && 'treenode_subnodes-expanded')}
			>
				{childrenWithProps}
			</div>
		</>
	);
};
